// ─────────────────────────────────────────────────────────────
// FIX 1: ZoomInfo returns { data: "<JSON string>" }
// We must JSON.parse the .data field before accessing .data[]
// FIX 2: Actual schema is attributes.company.name, attributes.signalScore
// NOT item.companyName / item.intentScore (old generic schema was wrong)
// FIX 3: HIGH_PRIORITY_TOPICS updated to match real ZoomInfo topic names
// FIX 4: recommendedContacts now captured for personalized outreach
// ─────────────────────────────────────────────────────────────

const rawInput = $input.first().json;

// Step 1 – parse the stringified JSON ZoomInfo wraps results in
let parsed;
try {
  parsed = typeof rawInput.data === 'string' ? JSON.parse(rawInput.data) : rawInput.data;
} catch(e) {
  return [{ json: { error: 'Failed to parse ZoomInfo response', raw: rawInput } }];
}

// Step 2 – extract the data array
const results = parsed?.data || [];

if (!Array.isArray(results) || results.length === 0) {
  return [{ json: { error: 'No intent results', totalResults: parsed?.meta?.totalResults || 0 } }];
}

// Step 3 – topic names exactly as ZoomInfo returns them (case-insensitive match)
const HIGH_PRIORITY_TOPICS = [
  'salesforce sales cloud',
  'salesforce marketing cloud',
  'salesforce implementation',
  'salesforce service cloud',
  'crm implementation',
  'crm migration',
  'ai automation',
  'sales intelligence',
  'revenue operations',
  'marketing automation'
];

// Step 4 – map each intent record using the REAL ZoomInfo schema
const normalized = results.map(item => {
  const attr = item.attributes || {};
  const company = attr.company || {};
  const topicName = attr.topic || 'Unknown';
  const contacts = attr.recommendedContacts || [];

  // Build top contact for personalization
  const topContact = contacts[0] || {};
  const allContactNames = contacts
    .slice(0, 3)
    .map(c => `${c.firstName} ${c.lastName} (${c.jobTitle || 'Unknown Title'})`)
    .join(' | ');

  return {
    // Company
    companyId: company.id,
    companyName: company.name || 'Unknown',
    domain: company.website || '',
    hasOtherTopics: company.hasOtherTopicConsumption || false,

    // Intent signal
    intentTopic: topicName,
    intentScore: attr.signalScore || 0,
    audienceStrength: attr.audienceStrength || 'Unknown',  // A/B/C/D/F grade
    spikesInDateRange: attr.spikesInDateRange || 1,
    signalDate: attr.signalDate || new Date().toISOString(),
    recordId: item.id,

    // Contacts
    topContactFirstName: topContact.firstName || '',
    topContactLastName: topContact.lastName || '',
    topContactTitle: topContact.jobTitle || '',
    topContactId: topContact.id || '',
    allContacts: allContactNames,
    contactCount: contacts.length,

    // Scoring helper for filter node
    isHighPriorityTopic: HIGH_PRIORITY_TOPICS.includes(topicName.toLowerCase()),
    overallIntentScore: attr.signalScore || 0,

    // Legacy field kept for compatibility with downstream parse node
    topTopic: { topic: topicName, score: attr.signalScore || 0 },
    intentTopics: [{
      topic: topicName,
      score: attr.signalScore || 0,
      isHighPriority: HIGH_PRIORITY_TOPICS.includes(topicName.toLowerCase())
    }],

    pulledAt: new Date().toISOString()
  };
});

return normalized.map(n => ({ json: n }));

// ─────────────────────────────────────────────────────────────────────────────
// ROBUST AI AGENT OUTPUT PARSER  v3
// Handles ALL known output formats from Claude / LLM agents:
//   1. ```json\n{...}\n```   ← actual observed format (markdown + lang tag)
//   2. ```\n{...}\n```       ← markdown without lang tag
//   3. {..pure JSON..}       ← clean ideal output
//   4. Preamble text\n{...}  ← explanation before JSON
//   5. {...}\n\nNote: ...    ← JSON + trailing explanation text
//   6. follow_up_days as string "3" or "3 days" instead of integer
//   7. urgency_level as "HIGH" (uppercase) instead of "high"
//   8. Partial/malformed JSON → graceful fallback with real contact data
// ─────────────────────────────────────────────────────────────────────────────

const rawOutput = $input.first().json.output
  || $input.first().json.text 
  || $input.first().json.content 
  || '';

const intentData = $('Loop Over Items').first().json;
console.log('intent Data', intentData);

// ── STEP 1: Strip markdown code fences (```json ... ``` or ``` ... ```) ──────
function stripCodeFences(str) {
  // Remove opening fence: ```json or ``` (with optional whitespace/newline)
  let cleaned = str.replace(/^```(?:json)?\s*/i, '');
  // Remove closing fence
  cleaned = cleaned.replace(/\s*```\s*$/, '');
  return cleaned.trim();
}

// ── STEP 2: Extract the JSON object from arbitrary surrounding text ───────────
function extractJSON(str) {
  // Find the first { and last } — handles preamble and trailing text
  const start = str.indexOf('{');
  const end   = str.lastIndexOf('}');
  if (start === -1 || end === -1 || end < start) return null;
  return str.slice(start, end + 1).trim();
}

// ── STEP 3: Sanitize field-level values after parsing ────────────────────────
function sanitize(obj, intentData) {
  // follow_up_days: ensure integer (handles "3", "3 days", 3.5, null)
  const rawDays = obj.follow_up_days;
  const parsedDays = parseInt(String(rawDays).replace(/\D.*$/, ''), 10);
  obj.follow_up_days = isNaN(parsedDays) ? 3 : Math.max(1, Math.min(parsedDays, 30));

  // urgency_level: normalise to lowercase, validate allowed values
  const rawUrgency = String(obj.urgency_level || '').toLowerCase().trim();
  obj.urgency_level = ['high', 'medium', 'low'].includes(rawUrgency) ? rawUrgency : 'medium';

  // best_channel: normalise to lowercase, validate
  const rawChannel = String(obj.best_channel || '').toLowerCase().trim();
  obj.best_channel = ['email', 'linkedin', 'phone'].includes(rawChannel) ? rawChannel : 'email';

  // subject_line: truncate to 60 chars if LLM ignored the limit
  if (obj.subject_line && obj.subject_line.length > 60) {
    obj.subject_line = obj.subject_line.slice(0, 57).trim() + '...';
  }

  // Ensure all required string fields exist and are non-empty
  const requiredStrings = [
    'subject_line', 'why_now_message', 'full_email_body',
    'linkedin_message', 'call_opener', 'internal_rep_note'
  ];
  requiredStrings.forEach(key => {
    if (!obj[key] || typeof obj[key] !== 'string' || obj[key].trim() === '') {
      obj[key] = `[${key} not generated — review manually]`;
    }
  });

  return obj;
}

// ── STEP 4: Fallback object built from real intent data ───────────────────────
function buildFallback(intentData) {
  const isSalesforce = (intentData.intentTopic || '').toLowerCase().includes('salesforce');
  const topicAngle   = isSalesforce ? 'CRM-driven sales operations' : 'revenue operations';
  const fn = intentData.topContactFirstName || 'there';
  const company = intentData.companyName || 'your organization';

  return {
    subject_line: `${fn}, a thought on ${topicAngle} at ${company}`.slice(0, 60),
    why_now_message: `Hi ${fn}, I wanted to reach out given what I've been seeing from teams scaling their ${topicAngle} — the timing felt relevant for ${company}. We've been working with several organizations in your space navigating exactly this.`,
    full_email_body: `Hi ${fn},\n\nI work with ${topicAngle} teams and wanted to reach out at the right moment.\n\nWould a quick 15-minute call be valuable this week?\n\nBest`,
    linkedin_message: `Hi ${fn} — I work with ${topicAngle} leaders and thought connecting could be timely for ${company}. Would love to share what we've seen work.`,
    call_opener: `Hi ${fn}, I work with teams focused on ${topicAngle} and wanted to reach out now because the challenges I'm hearing from your space feel highly relevant to ${company}.`,
    internal_rep_note: `${company} scored ${intentData.intentScore}/100 on "${intentData.intentTopic}" (Strength: ${intentData.audienceStrength}). Lead with ${topicAngle} angle. Primary: ${fn} ${intentData.topContactLastName || ''} (${intentData.topContactTitle || 'Unknown'}).`,
    urgency_level: (intentData.intentScore || 0) >= 85 ? 'high' : 'medium',
    best_channel: 'email',
    follow_up_days: 3
  };
}

// ── MAIN PARSE LOGIC ──────────────────────────────────────────────────────────
let outreach;
let parseMethod = 'unknown';
let parseError  = null;

try {
  // Attempt 1: strip fences → extract JSON object → parse
  const stripped   = stripCodeFences(rawOutput);
  const jsonString = extractJSON(stripped) || extractJSON(rawOutput);

  if (jsonString) {
    outreach = JSON.parse(jsonString);
    parseMethod = 'extracted_json';
  } else {
    // Attempt 2: maybe the whole string is valid JSON
    outreach = JSON.parse(rawOutput.trim());
    parseMethod = 'direct_parse';
  }
  outreach = sanitize(outreach, intentData);

} catch(e) {
  parseError  = e.message;
  parseMethod = 'fallback';
  outreach    = sanitize(buildFallback(intentData), intentData);
}

// ── BUILD FINAL OUTPUT ────────────────────────────────────────────────────────
const taskDue = new Date(
  Date.now() + (outreach.follow_up_days * 24 * 3600000)
).toISOString();

return {
  json: {
    // Intent data (spread first so outreach fields can override if needed)
    ...intentData,
    // Outreach fields
    ...outreach,
    // Metadata
    generatedAt:  new Date().toISOString(),
    taskTitle:    `Intent Alert [${intentData.audienceStrength || '?'}]: ${intentData.companyName} – ${intentData.intentTopic}`,
    taskDue,
    // Debug fields (visible in n8n execution log, harmless in Airtable)
    _parseMethod: parseMethod,
    _parseError:  parseError || null,
    _rawLength:   rawOutput.length
  }
};

